+#[cfg(not(windows))]
+fn open_with_args(url: &str, app: &str) -> Vec<String> {
+    #[cfg(target_os = "macos")]
+    {
+        vec![
+            "/usr/bin/open".to_string(),
+            "-a".to_string(),
+            app.to_string(),
+            url.to_string(),
+        ]
+    }
+
+    #[cfg(not(target_os = "macos"))]
+    {
+        vec![app.to_string(), url.to_string()]
+    }
+}
